const GTM_CONTAINER_ID = "GTM-XXXXXXX"; // Google Tag Manager
const GA4_MEASUREMENT_ID = "G-XXXXXXXXXX"; // Google Analytics 4
const META_PIXEL_ID = "0000000000000000"; // Meta (Facebook/Instagram) Pixel

async function submitToHubSpot(data, score) {
  const fields = [
    { name: "firstname", value: data.prenom },
    { name: "lastname", value: data.nom },
    { name: "phone", value: data.telephone },
    { name: "email", value: data.email },
    { name: "zip", value: data.codePostal },
    { name: "type_de_projet", value: data.projet || "" },
    { name: "statut_occupant", value: data.statut || "" },
    { name: "type_logement", value: data.logement || "" },
    { name: "surface_habitable", value: data.surface || "" },
    { name: "mode_chauffage_actuel", value: data.chauffage || "" },
    { name: "travaux_deja_realises", value: (data.travaux || []).join(";") },
    { name: "delai_projet", value: data.delai || "" },
    { name: "client_carrefour", value: data.clientCarrefour || "" },
    { name: "source_lead", value: data.source || "" },
    { name: "lead_score", value: String(score) },
  ];

  const payload = {
    fields,
    context: {
      pageUri: typeof window !== "undefined" ? window.location.href : "",
      pageName: "Mini-site Carrefour Energies - Alexandre",
    },
  };

  const url = `https://api.hsforms.com/submissions/v3/integration/submit/${HUBSPOT_PORTAL_ID}/${HUBSPOT_FORM_GUID}`;

  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
  });
  return res;
}

// =====================================================================
// LEAD SCORING
// =====================================================================
// Barème défini dans le cahier des charges. Les clés correspondent aux
// "id" utilisés dans PROJECT_OPTIONS / CHAUFFAGE_OPTIONS / DELAI_OPTIONS.

// Mode de chauffage actuel : plus c'est cher/polluant, plus le score est élevé
const CHAUFFAGE_SCORES = {
  fioul: 30,
  gaz: 20,
  electricite: 15,
  pac: 5,
  bois: 0,
  autre: 0,
};

// Type de projet : "plusieurs projets" = plus gros potentiel
const PROJET_SCORES = {
  plusieurs: 40,
  pac: 25,
  photovoltaique: 20,
  isolation: 15,
};

// Délai de réalisation : plus c'est urgent, plus le score est élevé
const DELAI_SCORES = {
  "3mois": 30,
  "6mois": 15,
  annee: 5,
  info: 0,
};

function calculateLeadScore(data) {
  let score = 0;

  score += CHAUFFAGE_SCORES[data.chauffage] || 0;
  score += PROJET_SCORES[data.projet] || 0;
  score += DELAI_SCORES[data.delai] || 0;

  const surface = Number(data.surface) || 0;
  if (surface > 150) score += 20;
  else if (surface >= 100) score += 15;
  else if (surface > 0) score += 5;

  return score;
}

// =====================================================================
// TRACKING : GA4 / GTM / META PIXEL
// =====================================================================
// Astuce QR Code : ajoute des paramètres UTM à l'URL imprimée sur le barnum
// pour mesurer les scans, ex :
// https://ton-site.fr/?utm_source=qr_barnum&utm_medium=offline&utm_campaign=marche_local
// GA4 attribuera automatiquement les sessions issues du QR Code à cette source.

function injectAnalyticsScripts() {
  if (typeof window === "undefined" || window.__analyticsInjected) return;
  window.__analyticsInjected = true;
  window.dataLayer = window.dataLayer || [];

  // --- Google Tag Manager ---
  if (GTM_CONTAINER_ID) {
    window.dataLayer.push({ "gtm.start": new Date().getTime(), event: "gtm.js" });
    const gtmScript = document.createElement("script");
    gtmScript.async = true;
    gtmScript.src = `https://www.googletagmanager.com/gtm.js?id=${GTM_CONTAINER_ID}`;
    document.head.appendChild(gtmScript);

    const noscript = document.createElement("noscript");
    const iframe = document.createElement("iframe");
    iframe.src = `https://www.googletagmanager.com/ns.html?id=${GTM_CONTAINER_ID}`;
    iframe.height = "0";
    iframe.width = "0";
    iframe.style.display = "none";
    iframe.style.visibility = "hidden";
    noscript.appendChild(iframe);
    document.body.insertBefore(noscript, document.body.firstChild);
  }

  // --- Google Analytics 4 (gtag.js) ---
  // Astuce : si GA4 est déjà configuré comme balise dans GTM, tu peux laisser
  // GA4_MEASUREMENT_ID vide pour éviter un double comptage.
  if (GA4_MEASUREMENT_ID) {
    const gaScript = document.createElement("script");
    gaScript.async = true;
    gaScript.src = `https://www.googletagmanager.com/gtag/js?id=${GA4_MEASUREMENT_ID}`;
    document.head.appendChild(gaScript);

    window.gtag = function () {
      window.dataLayer.push(arguments);
    };
    window.gtag("js", new Date());
    window.gtag("config", GA4_MEASUREMENT_ID);
  }

  // --- Meta Pixel ---
  if (META_PIXEL_ID) {
    /* eslint-disable */
    (function (f, b, e, v, n, t, s) {
      if (f.fbq) return;
      n = f.fbq = function () {
        n.callMethod ? n.callMethod.apply(n, arguments) : n.queue.push(arguments);
      };
      if (!f._fbq) f._fbq = n;
      n.push = n;
      n.loaded = true;
      n.version = "2.0";
      n.queue = [];
      t = b.createElement(e);
      t.async = true;
      t.src = v;
      s = b.getElementsByTagName(e)[0];
      s.parentNode.insertBefore(t, s);
    })(window, document, "script", "https://connect.facebook.net/en_US/fbevents.js");
    /* eslint-enable */
    window.fbq("init", META_PIXEL_ID);
    window.fbq("track", "PageView");
  }
}

// Pousse un évènement vers dataLayer (GTM) + GA4 + Meta Pixel
function trackEvent(eventName, params = {}) {
  if (typeof window === "undefined") return;
  window.dataLayer = window.dataLayer || [];
  window.dataLayer.push({ event: eventName, ...params });
  if (typeof window.gtag === "function") {
    window.gtag("event", eventName, params);
  }
}

// Évènement : début du tunnel de qualification
function trackFunnelStart(projectId) {
  trackEvent("funnel_start", { project_type: projectId || "non_specifie" });
}

// Évènement : changement d'étape dans le tunnel (utile pour mesurer le taux d'abandon)
function trackFunnelStep(stepKey, stepNumber) {
  trackEvent("funnel_step", { step_key: stepKey, step_number: stepNumber });
}

// Évènement : lead qualifié envoyé à HubSpot (GA4 "generate_lead" + Meta "Lead")
function trackLead(data, score) {
  trackEvent("generate_lead", {
    value: score,
    currency: "EUR",
    project_type: data.projet || "non_specifie",
    lead_score: score,
  });
  if (typeof window.fbq === "function") {
    window.fbq("track", "Lead", {
      content_name: data.projet || "non_specifie",
      value: score,
      currency: "EUR",
    });
  }
}

// Évènement : créneau de rappel confirmé (GA4 custom event + Meta "Schedule")
function trackAppointment(data) {
  trackEvent("appointment_scheduled", { project_type: data.projet || "non_specifie" });
  if (typeof window.fbq === "function") {
    window.fbq("track", "Schedule");
  }
}

// Évènement : clic sur le téléphone (depuis la barre flottante ou le bloc Alexandre)
function trackPhoneClick(location) {
  trackEvent("phone_call_click", { location });
  if (typeof window.fbq === "function") {
    window.fbq("track", "Contact");
  }
}

