function ProgressTicket({ stepIndex, total }) {
  const pct = ((stepIndex + 1) / total) * 100;
  return (
    <div className="mx-auto max-w-md px-4 pb-2 pt-3">
      <div className="mb-1.5 flex items-center justify-between">
        <span className="text-xs font-bold uppercase tracking-wide" style={{ color: COLORS.navy }}>
          Votre étude gratuite
        </span>
        <span className="text-xs font-extrabold" style={{ color: COLORS.turquoise }}>
          Étape {stepIndex + 1}/{total}
        </span>
      </div>
      <div className="h-2 w-full overflow-hidden rounded-full bg-slate-200">
        <div
          className="h-full rounded-full transition-all duration-300"
          style={{ width: `${pct}%`, backgroundColor: COLORS.turquoise }}
        />
      </div>
    </div>
  );
}

function ChoiceGrid({ options, value, multi, columns, onSelect }) {
  return (
    <div className={`grid gap-3 ${columns === 2 ? "grid-cols-2" : "grid-cols-1"}`}>
      {options.map((opt) => {
        const selected = multi ? (value || []).includes(opt.id) : value === opt.id;
        return (
          <button
            key={opt.id}
            onClick={() => onSelect(opt.id)}
            className="flex items-center gap-3 rounded-2xl border-2 p-4 text-left transition-colors"
            style={{
              borderColor: selected ? COLORS.turquoise : "#e2e8f0",
              backgroundColor: selected ? "#e6f9f7" : "#ffffff",
            }}
          >
            {opt.icon ? (
              <span className="flex-shrink-0 text-2xl">{opt.icon}</span>
            ) : (
              <span
                className="flex h-5 w-5 flex-shrink-0 items-center justify-center rounded-full border-2"
                style={{
                  borderColor: selected ? COLORS.turquoise : "#cbd5e1",
                  backgroundColor: selected ? COLORS.turquoise : "transparent",
                }}
              >
                {selected && <Check size={12} className="text-white" />}
              </span>
            )}
            <span className="text-sm font-semibold text-slate-800">{opt.label}</span>
            {multi && selected && <Check className="ml-auto flex-shrink-0" size={18} style={{ color: COLORS.turquoise }} />}
          </button>
        );
      })}
    </div>
  );
}

