// =====================================================================
// APP
// =====================================================================

const EMPTY_DATA = {
  projet: null,
  statut: null,
  logement: null,
  surface: "",
  chauffage: null,
  travaux: [],
  delai: null,
  clientCarrefour: null,
  source: null,
  prenom: "",
  nom: "",
  telephone: "",
  email: "",
  codePostal: "",
};

export default function App() {
  const [view, setView] = useState("home"); // home | funnel | booking | confirmation
  const [stepIndex, setStepIndex] = useState(0);
  const [submitting, setSubmitting] = useState(false);
  const [data, setData] = useState(EMPTY_DATA);

  // Injecte GTM / GA4 / Meta Pixel une seule fois au chargement
  useEffect(() => {
    injectAnalyticsScripts();
  }, []);

  // Suit la progression dans le tunnel (utile pour le taux d'abandon par étape)
  useEffect(() => {
    if (view === "funnel") {
      trackFunnelStep(FUNNEL_STEPS[stepIndex].key, stepIndex + 1);
    }
  }, [view, stepIndex]);

  function update(key, value) {
    setData((prev) => ({ ...prev, [key]: value }));
  }

  function selectSingle(key, value) {
    setData((prev) => ({ ...prev, [key]: value }));
    setTimeout(() => {
      setStepIndex((i) => Math.min(i + 1, FUNNEL_STEPS.length - 1));
    }, 150);
  }

  function toggleMulti(key, value) {
    setData((prev) => {
      const current = prev[key] || [];
      let next;
      if (value === "aucun") {
        next = current.includes("aucun") ? [] : ["aucun"];
      } else {
        const withoutAucun = current.filter((v) => v !== "aucun");
        next = withoutAucun.includes(value) ? withoutAucun.filter((v) => v !== value) : [...withoutAucun, value];
      }
      return { ...prev, [key]: next };
    });
  }

  function goBack() {
    if (stepIndex > 0) setStepIndex((i) => i - 1);
    else setView("home");
  }

  async function goNext() {
    if (stepIndex < FUNNEL_STEPS.length - 1) {
      setStepIndex((i) => i + 1);
      return;
    }
    setSubmitting(true);
    const score = calculateLeadScore(data);
    try {
      await submitToHubSpot(data, score);
    } catch (err) {
      console.error("Erreur envoi HubSpot :", err);
    }
    trackLead(data, score);
    setSubmitting(false);
    setView("booking");
  }

  function startFunnel() {
    trackFunnelStart(data.projet);
    setStepIndex(0);
    setView("funnel");
  }

  function startFunnelWithProject(projectId) {
    trackFunnelStart(projectId);
    setData((prev) => ({ ...prev, projet: projectId }));
    setStepIndex(1);
    setView("funnel");
  }

  function goToBooking() {
    setView("booking");
  }

  function finishBooking() {
    trackAppointment(data);
    setView("confirmation");
  }

  function restart() {
    setData(EMPTY_DATA);
    setStepIndex(0);
    setView("home");
  }


  return (
    <div className="min-h-screen" style={{ backgroundColor: COLORS.bg, fontFamily: "'Inter', sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Outfit:wght@600;700;800&display=swap');
        .font-display { font-family: 'Outfit', sans-serif; }
        .input-field { outline: none; transition: border-color 0.15s ease; }
        .input-field:focus { border-color: ${COLORS.turquoise}; }
      `}</style>

      <TopBar />

      {view === "home" && <HomeView onStart={startFunnel} onStartWithProject={startFunnelWithProject} onBook={goToBooking} />}

      {view === "funnel" && (
        <FunnelView
          stepIndex={stepIndex}
          data={data}
          update={update}
          onSelectSingle={selectSingle}
          onToggleMulti={toggleMulti}
          onNext={goNext}
          onBack={goBack}
          submitting={submitting}
        />
      )}

      {view === "booking" && <BookingView onConfirm={finishBooking} />}

      {view === "confirmation" && <ConfirmationView data={data} onRestart={restart} />}

      {view === "home" && <FloatingBar onCallback={startFunnel} onBook={goToBooking} />}
    </div>
  );
}
